package main

import (
	"fmt"
	"sort"
)

func main() {
	numbers := []int{10, 25, 3, 47, 8}
	fmt.Println("Slice uzunlugu:", len(numbers))

	sort.Ints(numbers)
	fmt.Println("Siralanmis slice:", numbers)

	// Eleman ekleme (append)
	numbers = append(numbers, 100)
	fmt.Println("\n100 eklendi:", numbers)

	// Dilimleme (slicing)
	fmt.Println("\nDilimleme:")
	fmt.Println("Ilk 3 eleman:", numbers[:3])
	fmt.Println("Son 2 eleman:", numbers[len(numbers)-2:])

	// Slice'i silme (belirli indeksi cikarma)
	index := 0
	numbers = append(numbers[:index], numbers[index+1:]...)
	fmt.Println("\nIlk eleman silindi:", numbers)

	// Toplam hesaplama
	total := 0
	for _, n := range numbers {
		total += n
	}
	fmt.Println("\nToplam:", total)

	// 2 boyutlu slice (matris)
	matrix := [][]int{{1, 2}, {3, 4}, {5, 6}}
	fmt.Println("\nMatris:")
	for _, row := range matrix {
		fmt.Println(row)
	}
}
